DROP TABLE IF EXISTS music_data;

CREATE TABLE music_data (
    idade TEXT,
    genero TEXT,
    regiao TEXT,
    genero_favorito TEXT,
    generos_escuta TEXT,
    generos_evita TEXT,
    motivo_gostar TEXT,
    motivo_nao_gostar TEXT,
    variedade_generos TEXT,
    tempo_escuta TEXT,
    plataforma_descoberta TEXT,
    frequencia_descoberta TEXT,
    preferencia_nacional TEXT
);
